import{_ as i,C as n,o as l,c as d,j as t,a as s,E as a,ag as o}from"./chunks/framework.DLWhSH9p.js";const f=JSON.parse('{"title":"Marketplace","description":"","frontmatter":{},"headers":[],"relativePath":"guide/marketplace.md","filePath":"guide/marketplace.md"}'),c={name:"guide/marketplace.md"};function g(h,e,p,m,u,b){const r=n("SchemeImage");return l(),d("div",null,[e[0]||(e[0]=t("h1",{id:"marketplace",tabindex:"-1"},[s("Marketplace "),t("a",{class:"header-anchor",href:"#marketplace","aria-label":'Permalink to "Marketplace"'},"​")],-1)),e[1]||(e[1]=t("p",null,"The Marketplace is where you hire voice actors, musicians, on-camera spokespersons, editors, and animators for your channel — and, if you're a creator, where you list yourself for hire.",-1)),e[2]||(e[2]=t("div",{class:"warning custom-block"},[t("p",{class:"custom-block-title"},"Early-access preview"),t("p",null,[s("The Marketplace is currently a "),t("strong",null,"UI preview"),s(". Artist listings, contracts, and payments are mocked in the frontend — no real transactions happen yet. Back-end integration (escrow, payout, ratings, disputes) is the next phase.")])],-1)),a(r,{name:"marketplace-browse",alt:"Marketplace browse"}),e[3]||(e[3]=o('<p>Open it from the top chrome right rail: <strong>Marketplace</strong>.</p><h2 id="the-pricing-model" tabindex="-1">The pricing model <a class="header-anchor" href="#the-pricing-model" aria-label="Permalink to &quot;The pricing model&quot;">​</a></h2><p>The Marketplace&#39;s defining commitment: <strong>creators keep 100%</strong> of their quoted price. Buyers pay a flat <strong>15% marketplace fee</strong> on top, plus no card fees (payments settle against your channel wallet, bank, or card).</p><p>There is <strong>one</strong> bill for creators: <strong>storage</strong>. It scales with the library they upload — enough to prevent abuse, not enough to matter in practice ($4/mo for 25 GB in the current preview). Everything else — listings, demos, messaging, contracts, payout — is free.</p><h2 id="sub-views" tabindex="-1">Sub-views <a class="header-anchor" href="#sub-views" aria-label="Permalink to &quot;Sub-views&quot;">​</a></h2><p>The Marketplace has its own sub-navigation (separate chrome from the Studio stage rail): <strong>Browse · Gigs · Partners · My studio</strong>. The <code>+ Post a gig</code> and <code>+ List a partner</code> actions live in the top-right of the chrome and are always one click away.</p><h3 id="browse" tabindex="-1">Browse <a class="header-anchor" href="#browse" aria-label="Permalink to &quot;Browse&quot;">​</a></h3><p>Filter rail on the left (category, style/vibe, language, turnaround, price), hero stats, a <strong>Spotlight rail</strong> of top creators (4.8★+ with 25+ completed jobs), then a grid of everyone else. Each card shows role, rating, jobs completed, rate, and — for voice actors — a mini-waveform demo or filmstrip preview.</p><p><strong>Categories</strong></p><ul><li><strong>Voice actors</strong> — narration, spokesperson, ad reads</li><li><strong>Spokespersons</strong> — on-camera hosts</li><li><strong>Musicians</strong> — custom tracks, ambient, orchestral, electronic</li><li><strong>Editors</strong> — pacing surgery, shorts-first cuts, long-form docs</li><li><strong>Animators</strong> — 2D motion, 3D, explainer, data-viz</li></ul><h3 id="gigs" tabindex="-1">Gigs <a class="header-anchor" href="#gigs" aria-label="Permalink to &quot;Gigs&quot;">​</a></h3>',11)),a(r,{name:"marketplace-gigs",alt:"Open gigs — filter rail + gig cards"}),e[4]||(e[4]=o('<p>Gigs is the flip side of Browse — instead of buyers searching for creators, creators see <strong>channels posting what they need</strong> and apply with a message + quote.</p><p><strong>For creators</strong></p><ol><li>Open <strong>Gigs</strong> in the marketplace chrome.</li><li>Filter by role, budget, deadline, status.</li><li>Click a gig card to see the full brief (description, deliverables, tags, budget).</li><li>Submit an application — short pitch + your quote.</li></ol><p>The buyer sees your application under their gig. If they shortlist or accept you, the next step is the standard <a href="#hire-contract">Hire &amp; contract</a> flow against your quote.</p><p><strong>For buyers — Post a gig</strong></p>',5)),a(r,{name:"marketplace-post-gig",alt:"Post a gig form with live preview"}),e[5]||(e[5]=o('<p>Click <strong>+ Post a gig</strong> in the top-right of the marketplace chrome. The form has:</p><ul><li><strong>Title</strong> — the headline creators see in the list</li><li><strong>Role</strong> — voice / spokesperson / music / editor / animator</li><li><strong>Description</strong> — the brief (context, tone, samples, deadlines)</li><li><strong>Deliverables</strong> — file formats, revisions, timeline</li><li><strong>Budget min / max</strong> — displayed as a range on the card</li><li><strong>Deadline</strong> — free-text (e.g. &quot;Apr 28&quot; or &quot;Ongoing&quot;)</li><li><strong>Tags</strong> — comma-separated search keywords</li><li><strong>Your name / channel</strong> — attribution shown on the gig</li></ul><p>A live preview card sits to the right so you can see the cards as applicants will. Nothing is charged at post-time — funds only move through escrow once you <strong>accept</strong> a specific applicant.</p><h3 id="partners" tabindex="-1">Partners <a class="header-anchor" href="#partners" aria-label="Permalink to &quot;Partners&quot;">​</a></h3><p>Partners is the <strong>brand-sponsorship</strong> side of the Marketplace — distinct from creators-for-hire. Two populations live here:</p><ul><li><strong>Channels seeking sponsors</strong> — audience, niche, sample reads, CPM ranges.</li><li><strong>Brands seeking channels</strong> — products, campaigns, deliverable expectations, budgets.</li></ul><p>Both are rendered as partner cards with hue-themed covers, tier badges (see <a href="#gamification-tiers-badges-streaks">Gamification</a>), active listings count, and a spotlight flag for top performers. Clicking a card opens <strong>Partner detail</strong>: tagline, description, listings the partner has open, reviews against prior placements, and a sticky <code>Pitch a partnership</code> button.</p><p>Click <strong>+ List a partner</strong> in the chrome to add your own channel or brand to the directory. You pick the kind (<code>channel</code> or <code>brand</code>), describe your audience or product, and attach one or more active listings with price ranges and status (<code>open</code>, <code>paused</code>, <code>filled</code>).</p><p>Reviews here are <strong>placement-scoped</strong>, not gig-scoped — they reference a specific placement ID so both sides can back-reference the engagement. Same star-rating mechanics as artist reviews.</p><h3 id="artist-profile" tabindex="-1">Artist profile <a class="header-anchor" href="#artist-profile" aria-label="Permalink to &quot;Artist profile&quot;">​</a></h3><p>Cover image, demo reel with inline audio playback, reviews, and a sticky hire sidebar. The sidebar has:</p><ul><li>Headline rate</li><li>Minimum order &amp; typical reply time</li><li>Package tiers (e.g. &quot;Script under 500w · 24h · $60&quot;, &quot;Documentary narration · 3 days · $210&quot;)</li><li><strong>Request this creator →</strong> (starts the hire flow)</li><li><strong>Send a message first</strong> (messaging layer is mocked for now)</li></ul><h3 id="my-studio" tabindex="-1">My studio <a class="header-anchor" href="#my-studio" aria-label="Permalink to &quot;My studio&quot;">​</a></h3>',13)),a(r,{name:"marketplace-studio",alt:"Marketplace — My studio dashboard"}),e[6]||(e[6]=o('<p>If you&#39;re a creator, this is your dashboard:</p><ul><li><strong>Earnings hero</strong> — this month&#39;s take, emphasised that we didn&#39;t touch it</li><li><strong>Storage meter</strong> — your only bill</li><li><strong>Five headline metrics</strong> — this-month earnings, active gigs, 90-day rating, average reply time, on-time rate</li><li><strong>Active gigs table</strong> — status per row (in progress · awaiting script · awaiting review · paid · delivered)</li><li><strong>Earnings chart</strong> — 6-month bar chart</li><li><strong>Next payout card</strong> — amount, date, early-withdraw option ($5 fee)</li><li><strong>Spotlight status</strong> — your progress toward the next quarterly spotlight rotation</li></ul><h2 id="gamification-tiers-badges-streaks" tabindex="-1">Gamification: tiers, badges, streaks <a class="header-anchor" href="#gamification-tiers-badges-streaks" aria-label="Permalink to &quot;Gamification: tiers, badges, streaks&quot;">​</a></h2><p>Creators and brand partners earn <strong>visible, criterion-based recognition</strong> based on their public stats. Nothing here is pay-to-play — tiers and badges are computed from <code>rating</code>, <code>jobsCompleted</code>, <code>onTimePct</code>, and <code>replyHours</code>. The rationale for every badge is visible in the UI, so there&#39;s no mystery about what unlocked it.</p><h3 id="tiers" tabindex="-1">Tiers <a class="header-anchor" href="#tiers" aria-label="Permalink to &quot;Tiers&quot;">​</a></h3><p>Four tiers, gated on hard thresholds — all three criteria must be met to advance:</p><table tabindex="0"><thead><tr><th>Tier</th><th style="text-align:right;">Rating</th><th style="text-align:right;">Completed jobs</th><th style="text-align:right;">On-time</th></tr></thead><tbody><tr><td><strong>Bronze</strong></td><td style="text-align:right;">—</td><td style="text-align:right;">—</td><td style="text-align:right;">—</td></tr><tr><td><strong>Silver</strong></td><td style="text-align:right;">≥ 4.5</td><td style="text-align:right;">≥ 10</td><td style="text-align:right;">≥ 90%</td></tr><tr><td><strong>Gold</strong></td><td style="text-align:right;">≥ 4.8</td><td style="text-align:right;">≥ 50</td><td style="text-align:right;">≥ 95%</td></tr><tr><td><strong>Platinum</strong></td><td style="text-align:right;">≥ 4.9</td><td style="text-align:right;">≥ 150</td><td style="text-align:right;">≥ 98%</td></tr></tbody></table><p>The profile card also shows a <code>tierScore</code> (0–100): <strong>40% rating · 30% volume · 20% on-time · 10% reply speed</strong>. It&#39;s a smooth signal between tier jumps so progress is legible.</p><h3 id="badges" tabindex="-1">Badges <a class="header-anchor" href="#badges" aria-label="Permalink to &quot;Badges&quot;">​</a></h3><p>Badges are <strong>current-state</strong> flags — they turn on and off as stats move. Examples: <code>Five-star recent</code> (last 10 reviews all ≥ 5★), <code>Reply within 1h</code>, <code>No-missed-deadline month</code>. Each badge lists its rationale on hover so there&#39;s no guesswork.</p><h3 id="achievements" tabindex="-1">Achievements <a class="header-anchor" href="#achievements" aria-label="Permalink to &quot;Achievements&quot;">​</a></h3><p>Achievements are <strong>permanent</strong> milestones — once unlocked, they stay. Rarity tiers: <code>common</code> · <code>uncommon</code> · <code>rare</code> · <code>legendary</code>. Examples: <code>First completed gig</code>, <code>Repeat client</code> (same buyer books twice), <code>10 five-star reviews in a row</code>. Unlocks show the date in the profile&#39;s achievements strip.</p><h3 id="streaks" tabindex="-1">Streaks <a class="header-anchor" href="#streaks" aria-label="Permalink to &quot;Streaks&quot;">​</a></h3><p>Streaks are <strong>consecutive counters</strong> that reset when broken but remain visible as historical markers. Examples: <code>On-time delivery streak · 14 days</code>, <code>First-reply-under-1h streak · 9 messages</code>. An inactive streak renders muted to show the last peak.</p><h3 id="next-tier-hint" tabindex="-1">Next-tier hint <a class="header-anchor" href="#next-tier-hint" aria-label="Permalink to &quot;Next-tier hint&quot;">​</a></h3><p>Every profile shows what&#39;s still needed for the next tier — e.g. <code>Silver → Gold: +12 jobs, rating ≥ 4.8</code>. No gamified carrot; just a concrete list so creators know exactly what moves the needle.</p><h2 id="hire-contract" tabindex="-1">Hire &amp; contract <a class="header-anchor" href="#hire-contract" aria-label="Permalink to &quot;Hire &amp; contract&quot;">​</a></h2><p>A 4-step stepper: <strong>Brief → Scope &amp; schedule → Contract → Pay &amp; start</strong>. The contract is CRAFT-standard with fields for parties, deliverable, format, revisions, delivery date, usage rights, and credit line. The payment summary breaks out:</p><ul><li><code>{words} × {rate}</code> → creator receives</li><li><code>Marketplace fee (15%)</code></li><li><strong>You pay</strong> total</li></ul><p>Funds are held in escrow (plan; mocked now) until you approve delivery.</p><h2 id="backend-status" tabindex="-1">Backend status <a class="header-anchor" href="#backend-status" aria-label="Permalink to &quot;Backend status&quot;">​</a></h2><p>Everything above is rendered from <code>app/frontend/src/lib/marketplace.ts</code>. When the backend API for <code>/marketplace/artists</code>, <code>/marketplace/gigs</code>, <code>/marketplace/contracts</code>, <code>/marketplace/payouts</code> lands, those become real endpoints and the data layer swaps out transparently — the panel UI doesn&#39;t change.</p>',22))])}const k=i(c,[["render",g]]);export{f as __pageData,k as default};
